class Solution:
    def minOperations(self, nums, k):
        need = set(range(1, k + 1))
        found = set()
        steps = 0
        for x in reversed(nums):
            steps += 1
            if x in need:
                found.add(x)
                if len(found) == k:
                    return steps
        return steps

