var minOperations = function(nums, k) {
    const found = new Set();
    let steps = 0;
    for (let i = nums.length - 1; i >= 0; i--) {
        steps++;
        const x = nums[i];
        if (x <= k) {
            found.add(x);
            if (found.size === k) return steps;
        }
    }
    return steps;
};
